INSERT INTO "argomento" ("id", "nome_argomento", "descrizione") VALUES
(16,	'Le Piante e la Fotosintesi',	'La fotosintesi è il processo con cui le piante trasformano luce, acqua e anidride carbonica in ossigeno e zuccheri, permettendo loro di crescere e sostenere la vita sulla Terra.'),
(19,	'Personaggi Iconici dei Videogiochi',	'I personaggi iconici dei videogiochi hanno definito intere generazioni, diventando simboli riconoscibili e protagonisti di saghe che hanno influenzato la cultura pop e l’evoluzione del medium videoludico.'),
(20,	'Tradizioni e Feste Italiane',	'Le tradizioni e le feste italiane riflettono la storia e la cultura del Paese, con celebrazioni che variano da regione a regione e includono riti popolari, eventi religiosi, maschere, musica e piatti tipici.'),
(21,	'Concetti Base della Programmazione',	'La programmazione consiste nel creare istruzioni che un computer può eseguire. I concetti fondamentali includono variabili, cicli, condizioni e funzioni, che permettono di costruire programmi semplici e complessi.'),
(27,	'Argomento vuoto',	'Argomento senza domande'),
(17,	'Storia del Cinema Italiano',	'Il cinema italiano ha influenzato profondamente la cultura mondiale, passando dal Neorealismo ai grandi autori come Fellini e De Sica, fino alle produzioni contemporanee che continuano a rinnovarne lo stile.'),
(33,	'Test orderBy',	'test orderBy');
